async function confirmArb() {
  closeM();
  const r = filteredRows[selIdx]; if (!r) return;
  const bex = document.getElementById('buyEx').value, sex = document.getElementById('sellEx').value;
  const buyPraw = parseFloat(document.getElementById('lBuy').value);
  const sellPraw = parseFloat(document.getElementById('lSell').value);
  const buyP = (!buyPraw || isNaN(buyPraw) || buyPraw <= 0) ? r.buyAt : buyPraw;
  const sellP = (!sellPraw || isNaN(sellPraw) || sellPraw <= 0) ? r.sellAt : sellPraw;
  if (!buyP || buyP <= 0 || !sellP || sellP <= 0) { notify('⚠ Preços inválidos', 'w'); return; }
  const usdt = getOrderUSDT(), token = getOrderToken();
  if (!token || token <= 0) { notify('⚠ Quantidade inválida', 'w'); return; }
  const mode = document.getElementById('arbMode').value;
  const isSpotBuy = mode === 'SS' || mode === 'SF';
  const isSpotSell = mode === 'SS' || mode === 'FS';
  const hasBuyKey = !!lsGet('keys_' + bex.toLowerCase());
  const hasSellKey = !!lsGet('keys_' + sex.toLowerCase());
  if (!hasBuyKey || !hasSellKey) {
    notify('⚠ Configure as keys de ' + ((!hasBuyKey) ? bex : sex), 'w');
    registerTrade(r, bex, sex, buyP, sellP, usdt, token, mode, 'cancelled'); return;
  }
  arbInProgress = true;
  notify('⚡ Enviando ARB ' + r.sym + '...', '');
  try {
    // Executa sequencialmente para permitir rollback
    let buyRes;
    try {
      buyRes = await placeRealOrder(bex, r.sym, 'buy', token, buyP, isSpotBuy);
    } catch (buyErr) {
      notify('✗ BUY falhou (' + bex + '): ' + errMsg(buyErr), 'e');
      registerTrade(r, bex, sex, buyP, sellP, usdt, token, mode, 'cancelled');
      return;
    }
    let sellRes;
    try {
      sellRes = await placeRealOrder(sex, r.sym, 'sell', token, sellP, isSpotSell);
    } catch (sellErr) {
      notify('✗ SELL falhou (' + sex + '): ' + errMsg(sellErr) + ' — revertendo BUY...', 'e');
      // Rollback: tenta vender o que comprou a mercado
      try {
        await placeRealOrder(bex, r.sym, 'sell', token, buyP * 0.999, isSpotBuy);
        notify('↩ Rollback BUY executado (' + bex + ')', 'w');
      } catch (rbErr) {
        notify('⚠ ROLLBACK FALHOU em ' + bex + ': ' + errMsg(rbErr) + ' — VERIFIQUE MANUALMENTE', 'e');
      }
      registerTrade(r, bex, sex, buyP, sellP, usdt, token, mode, 'cancelled');
      return;
    }
    notify('✓ ARB executado! BUY #' + (buyRes.orderId || '?') + ' | SELL #' + (sellRes.orderId || '?'), 'g');
    registerTrade(r, bex, sex, buyP, sellP, usdt, token, mode, 'open', buyRes.orderId, sellRes.orderId);
  } finally {
    arbInProgress = false;
  }
}

